class Solution:
    def countCharacters(self, words: List[str], chars: str) -> int:
        char_count = {}
        for char in chars:
            if char in char_count:
                char_count[char] += 1
            else:
                char_count[char] = 1

        total_length = 0
        for word in words:
            word_count = {}
            for char in word:
                if char in word_count:
                    word_count[char] += 1
                else:
                    word_count[char] = 1

            if all(word_count[char] <= char_count[char] for char in word_count):
                total_length += len(word)

        return total_length
```
